import anthropic
import threading
import time
from dataclasses import dataclass, field
from enum import Enum

class EnforcementLevel(Enum):
    WARN = "warn"
    THROTTLE = "throttle"
    BLOCK = "block"
    DEGRADE = "degrade"

@dataclass
class BudgetConfig:
    monthly_budget_usd: float
    warn_threshold: float = 0.75
    critical_threshold: float = 0.90
    hard_cap_threshold: float = 1.00
    hard_cap_action: EnforcementLevel = EnforcementLevel.BLOCK
    non_prod_rate_limit_rps: float = 10.0
    fallback_model: str = "claude-haiku-4-5-20251001"
    environment: str = "production"

class BudgetGuardrail:
    def __init__(self, config: BudgetConfig, ledger_reader):
        self.config = config
        self.ledger = ledger_reader
        self.spent_usd = ledger_reader.current_month_spend()

    def utilisation(self) -> float:
        return self.spent_usd / self.config.monthly_budget_usd

    def check_and_enforce(self, request: dict) -> dict:
        u = self.utilisation()

        if u < self.config.warn_threshold:
            return {"allow": True, "action": "pass", "model_override": None}

        if u < self.config.critical_threshold:
            self._emit_alert("warning", u)
            return {"allow": True, "action": "warn", "model_override": None}

        if u < self.config.hard_cap_threshold:
            self._emit_alert("critical", u)
            # Non-production traffic rate-limited at critical threshold
            env = request.get("environment", "production")
            if env != "production":
                self._apply_rate_limit(self.config.non_prod_rate_limit_rps)
            return {"allow": True, "action": "throttle", "model_override": None}

        # Hard cap reached
        self._emit_alert("hard_cap", u)
        action = self.config.hard_cap_action
        if action == EnforcementLevel.BLOCK:
            return {"allow": False, "action": "blocked", "model_override": None}
        elif action == EnforcementLevel.DEGRADE:
            return {"allow": True, "action": "degraded",
                    "model_override": self.config.fallback_model}
        else:
            return {"allow": True, "action": "over_budget_allowed", "model_override": None}

    def _emit_alert(self, level: str, u: float):
        print(f"[BUDGET] level={level} util={u:.1%} "
              f"spent=${self.spent_usd:.2f} budget=${self.config.monthly_budget_usd:.2f}")

    def _apply_rate_limit(self, rps: float):
        time.sleep(1.0 / rps)

class GuardedClaudeClient:
    def __init__(self, guardrail: BudgetGuardrail, ledger_writer):
        self.guardrail = guardrail
        self.ledger = ledger_writer
        self._client = anthropic.Anthropic()

    def messages_create(self, *, tags: dict, **kwargs) -> anthropic.types.Message:
        decision = self.guardrail.check_and_enforce(tags)
        if not decision["allow"]:
            raise RuntimeError(
                f"Request blocked: monthly budget exhausted "
                f"({self.guardrail.utilisation():.1%}). "
                "Contact AI FinOps for a budget increase."
            )
        if decision.get("model_override"):
            kwargs["model"] = decision["model_override"]
        response = self._client.messages.create(**kwargs)
        self.ledger.write(response, tags)
        return response
